        ],
        "services": [
          {
            "id": "jira-fronting",
            "name": "Jira Fronting",
            "role": "public governed capability service",
            "capabilities": [
              "jira.backlog.search_context",
              "jira.issue.get_context",
              "jira.incident_bug.prepare",
